/* =========================================================
   Tan Lerida — Colors & Type
   A complete leather house. India by origin, Australia by
   invitation. Restrained, rooted, craft-obsessed.
   ========================================================= */

/* ---------- Webfonts (Google Fonts) ---------------------- */
@import url("https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;0,600;0,700;1,300;1,400&family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap");

:root {
  /* ---------- Core palette ---------- */
  --tl-ink:        #0A0A0A;   /* Ink Black — hero surface, packaging, dark mode */
  --tl-ink-2:      #141414;   /* one step up from ink, for layered dark surfaces */
  --tl-ink-3:      #1F1F1F;   /* card surface on dark */
  --tl-bone:       #F8F8F6;   /* warm off-white — light surfaces, dark-mode text */
  --tl-bone-2:     #EFEDE8;   /* second-tier light surface, dividers on light */
  --tl-paper:      #E7E3DA;   /* heavier warm tone — section breaks, subtle blocks */
  --tl-gold:       #C9A84C;   /* Signature Gold — wordmark, brand accents only */
  --tl-gold-deep:  #9C7F2F;   /* gold press / hover state */
  --tl-tannery:    #2C4A3E;   /* Tannery Green — CTAs, focus rings, key callouts */
  --tl-tannery-2:  #1F362C;   /* CTA pressed */
  --tl-rust:       #6B3A22;   /* Tannery accent — leather burnish, secondary tag */
  --tl-cognac:     #8B5A2B;   /* warm leather tone — used in imagery only */

  /* ---------- Neutrals ---------- */
  --tl-mute:       #8A8A8A;   /* muted text on light & dark */
  --tl-mute-2:     #6B6B6B;   /* darker muted, captions on light */
  --tl-line:       #DAD6CC;   /* hairline divider on light */
  --tl-line-dark:  #2A2A2A;   /* hairline divider on dark */

  /* ---------- Semantic — light surface (default) ---------- */
  --bg:            var(--tl-bone);
  --bg-2:          var(--tl-bone-2);
  --bg-3:          var(--tl-paper);
  --fg:            var(--tl-ink);
  --fg-2:          var(--tl-mute-2);
  --fg-3:          var(--tl-mute);
  --line:          var(--tl-line);
  --accent:        var(--tl-tannery);
  --accent-press:  var(--tl-tannery-2);
  --brand:         var(--tl-gold);

  /* ---------- Type families ---------- */
  --tl-serif:      "Cormorant Garamond", "Cormorant", "EB Garamond", Georgia, serif;
  --tl-sans:       "Inter", -apple-system, BlinkMacSystemFont, "Segoe UI", system-ui, sans-serif;
  --tl-mono:       "JetBrains Mono", "Inter Mono", ui-monospace, "SF Mono", Menlo, monospace;

  /* ---------- Type scale (modular ~1.20) ---------- */
  --fs-12: 0.75rem;
  --fs-13: 0.8125rem;
  --fs-14: 0.875rem;
  --fs-15: 0.9375rem;
  --fs-16: 1rem;
  --fs-18: 1.125rem;
  --fs-20: 1.25rem;
  --fs-24: 1.5rem;
  --fs-28: 1.75rem;
  --fs-32: 2rem;
  --fs-40: 2.5rem;
  --fs-52: 3.25rem;
  --fs-64: 4rem;
  --fs-84: 5.25rem;

  /* ---------- Spacing — 4px base ---------- */
  --sp-1: 4px;
  --sp-2: 8px;
  --sp-3: 12px;
  --sp-4: 16px;
  --sp-5: 24px;
  --sp-6: 32px;
  --sp-7: 48px;
  --sp-8: 64px;
  --sp-9: 96px;
  --sp-10: 128px;

  /* ---------- Radii — generous on cards, never on text inputs except 2px ---------- */
  --r-0: 0px;
  --r-1: 2px;       /* hairline radius — inputs, chips, tags */
  --r-2: 4px;       /* small surfaces */
  --r-3: 8px;       /* cards */
  --r-4: 14px;      /* large cards, image frames */
  --pill: 999px;

  /* ---------- Elevation. Used sparingly. ---------- */
  --shadow-0: 0 0 0 1px var(--line);
  --shadow-1: 0 1px 2px rgba(10,10,10,0.04), 0 1px 1px rgba(10,10,10,0.03);
  --shadow-2: 0 6px 18px -6px rgba(10,10,10,0.12), 0 2px 4px rgba(10,10,10,0.04);
  --shadow-3: 0 24px 48px -16px rgba(10,10,10,0.20), 0 4px 8px rgba(10,10,10,0.06);
  --shadow-press: inset 0 1px 2px rgba(10,10,10,0.10);

  /* ---------- Motion. Slow and certain. ---------- */
  --ease-out: cubic-bezier(0.2, 0.7, 0.2, 1);
  --ease-in:  cubic-bezier(0.6, 0, 0.8, 0.2);
  --ease-std: cubic-bezier(0.3, 0.0, 0.2, 1);
  --d-fast: 140ms;
  --d-mid:  240ms;
  --d-slow: 420ms;

  /* ---------- Layout ---------- */
  --container: 1240px;
  --container-narrow: 880px;
  --gutter: 24px;
}

/* Dark surface preset — apply to a wrapper */
.tl-dark {
  --bg:    var(--tl-ink);
  --bg-2:  var(--tl-ink-2);
  --bg-3:  var(--tl-ink-3);
  --fg:    var(--tl-bone);
  --fg-2:  #BFBDB6;
  --fg-3:  var(--tl-mute);
  --line:  var(--tl-line-dark);
  background: var(--bg);
  color: var(--fg);
}

/* =========================================================
   Type — semantic styles
   Headings always serif. Body always sans. Tracking tightens
   as size grows; opens up at small sizes for legibility.
   ========================================================= */

html { font-family: var(--tl-sans); color: var(--fg); background: var(--bg); }
body { font-size: var(--fs-16); line-height: 1.55; }

.tl-h-display, h1.display {
  font-family: var(--tl-serif);
  font-weight: 400;
  font-size: clamp(var(--fs-52), 6vw, var(--fs-84));
  line-height: 1.02;
  letter-spacing: -0.012em;
  color: var(--fg);
}
.tl-h-display em, h1.display em {
  font-style: italic;
  color: var(--fg);
}

.tl-h1, h1 {
  font-family: var(--tl-serif);
  font-weight: 400;
  font-size: clamp(var(--fs-40), 4vw, var(--fs-64));
  line-height: 1.05;
  letter-spacing: -0.01em;
}

.tl-h2, h2 {
  font-family: var(--tl-serif);
  font-weight: 400;
  font-size: var(--fs-40);
  line-height: 1.1;
  letter-spacing: -0.005em;
}

.tl-h3, h3 {
  font-family: var(--tl-serif);
  font-weight: 500;
  font-size: var(--fs-28);
  line-height: 1.2;
}

.tl-h4, h4 {
  font-family: var(--tl-sans);
  font-weight: 500;
  font-size: var(--fs-18);
  line-height: 1.3;
  letter-spacing: 0;
}

.tl-eyebrow {
  font-family: var(--tl-sans);
  font-size: var(--fs-12);
  font-weight: 500;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  color: var(--fg-2);
}

.tl-lead {
  font-family: var(--tl-sans);
  font-size: var(--fs-20);
  line-height: 1.5;
  font-weight: 300;
  color: var(--fg-2);
  text-wrap: pretty;
}

.tl-body, p {
  font-family: var(--tl-sans);
  font-size: var(--fs-16);
  line-height: 1.6;
  color: var(--fg);
  text-wrap: pretty;
}

.tl-small {
  font-family: var(--tl-sans);
  font-size: var(--fs-14);
  line-height: 1.5;
  color: var(--fg-2);
}

.tl-caption {
  font-family: var(--tl-sans);
  font-size: var(--fs-12);
  line-height: 1.4;
  color: var(--fg-3);
  letter-spacing: 0.02em;
}

.tl-pull {
  font-family: var(--tl-serif);
  font-style: italic;
  font-size: clamp(var(--fs-24), 2.4vw, var(--fs-32));
  line-height: 1.25;
  color: var(--fg);
}

.tl-spec, code, .tl-mono {
  font-family: var(--tl-mono);
  font-size: var(--fs-13);
  letter-spacing: 0.01em;
  color: var(--fg-2);
}

/* Selection */
::selection { background: var(--tl-gold); color: var(--tl-ink); }

/* Shared chrome for preview cards. Each card is 700px wide; height varies. */
@import url("../colors_and_type.css");

* { box-sizing: border-box; margin: 0; padding: 0; }
html, body { width: 100%; }
body {
  background: var(--tl-bone);
  color: var(--tl-ink);
  font-family: var(--tl-sans);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}
.card {
  width: 700px;
  padding: 32px;
  background: var(--tl-bone);
  position: relative;
}
.card.dark {
  background: var(--tl-ink);
  color: var(--tl-bone);
}
.card.paper { background: var(--tl-paper); }
.card.bone-2 { background: var(--tl-bone-2); }

.row { display: flex; align-items: center; gap: 16px; }
.col { display: flex; flex-direction: column; gap: 8px; }
.stack-24 { display: flex; flex-direction: column; gap: 24px; }
.stack-16 { display: flex; flex-direction: column; gap: 16px; }
.stack-8  { display: flex; flex-direction: column; gap: 8px; }

.kicker {
  font-size: 11px; font-weight: 500; letter-spacing: 0.2em;
  text-transform: uppercase; color: var(--tl-mute-2);
}
.dark .kicker { color: var(--tl-mute); }
.mono { font-family: var(--tl-mono); font-size: 12px; color: var(--tl-mute-2); }
.dark .mono { color: var(--tl-mute); }

/* Tan Lerida — Web UI Kit shared styles. Imports tokens. */
@import url("../../colors_and_type.css");

* { box-sizing: border-box; margin: 0; padding: 0; }
html, body { width: 100%; }
body {
  background: var(--tl-bone);
  color: var(--tl-ink);
  font-family: var(--tl-sans);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  font-size: 16px;
  line-height: 1.55;
}
img { display: block; max-width: 100%; }
a { color: inherit; }

.container { max-width: 1240px; margin: 0 auto; padding: 0 24px; }
.container-narrow { max-width: 880px; margin: 0 auto; padding: 0 24px; }

/* Header */
.tl-header {
  position: sticky; top: 0; z-index: 50;
  background: var(--tl-bone);
  border-bottom: 1px solid var(--tl-line);
}
.tl-header-row {
  display: flex; align-items: center; justify-content: space-between;
  padding: 16px 24px; max-width: 1240px; margin: 0 auto;
}
.tl-logo { height: 36px; width: auto; }
.tl-nav { display: flex; gap: 28px; }
.tl-nav a {
  font-size: 14px; color: var(--tl-ink); text-decoration: none;
  position: relative; padding: 4px 0;
}
.tl-nav a::after {
  content: ''; position: absolute; left: 0; right: 100%; bottom: 0;
  height: 1px; background: var(--tl-ink);
  transition: right 240ms cubic-bezier(0.2,0.7,0.2,1);
}
.tl-nav a:hover::after { right: 0; }
.tl-actions { display: flex; gap: 18px; align-items: center; font-size: 14px; }
.tl-actions a { text-decoration: none; cursor: pointer; }
.tl-bag-count { color: var(--tl-mute-2); }

/* Buttons */
.tl-btn {
  display: inline-flex; align-items: center; justify-content: center; gap: 8px;
  background: var(--tl-tannery); color: var(--tl-bone); border: 0;
  border-radius: 2px; padding: 14px 24px;
  font-family: var(--tl-sans); font-size: 14px; font-weight: 500;
  letter-spacing: 0.02em; cursor: pointer;
  transition: background 140ms cubic-bezier(0.3,0,0.2,1);
}
.tl-btn:hover { background: var(--tl-tannery-2); }
.tl-btn:active { box-shadow: inset 0 1px 2px rgba(0,0,0,0.10); }
.tl-btn--outline {
  background: transparent; color: var(--tl-ink); border: 1px solid var(--tl-ink);
}
.tl-btn--outline:hover { background: var(--tl-ink); color: var(--tl-bone); }
.tl-btn--full { width: 100%; padding: 16px; }
.tl-link {
  display: inline-flex; align-items: center; gap: 8px;
  color: var(--tl-ink); text-decoration: none; font-weight: 500; font-size: 14px;
  border-bottom: 1px solid var(--tl-ink); padding-bottom: 2px;
}
.tl-link--muted { color: var(--tl-mute-2); border-bottom-color: transparent; }

/* Eyebrow */
.tl-eyebrow {
  font-size: 12px; font-weight: 500; letter-spacing: 0.18em;
  text-transform: uppercase; color: var(--tl-mute-2);
}
.tl-eyebrow--accent { color: var(--tl-tannery); }
.tl-eyebrow--bone { color: #BFBDB6; }

/* Headlines */
.tl-display {
  font-family: var(--tl-serif); font-weight: 400;
  font-size: clamp(48px, 6vw, 84px); line-height: 1.02;
  letter-spacing: -0.012em;
}
.tl-h1 { font-family: var(--tl-serif); font-weight: 400; font-size: 56px; line-height: 1.05; letter-spacing: -0.01em; }
.tl-h2 { font-family: var(--tl-serif); font-weight: 400; font-size: 40px; line-height: 1.1; letter-spacing: -0.005em; }
.tl-h3 { font-family: var(--tl-serif); font-weight: 500; font-size: 28px; line-height: 1.2; }
.tl-h4 { font-family: var(--tl-serif); font-weight: 500; font-size: 20px; line-height: 1.2; }
.tl-lead { font-size: 20px; line-height: 1.55; font-weight: 300; color: var(--tl-mute-2); text-wrap: pretty; }
.tl-body { font-size: 16px; line-height: 1.6; }
.tl-small { font-size: 14px; color: var(--tl-mute-2); }
.tl-caption { font-size: 12px; color: var(--tl-mute); letter-spacing: 0.02em; }
.tl-spec { font-family: var(--tl-mono); font-size: 13px; color: var(--tl-mute-2); letter-spacing: 0.01em; }
.tl-pull { font-family: var(--tl-serif); font-style: italic; font-size: 28px; line-height: 1.3; color: var(--tl-ink); }

em.accent { font-style: italic; color: var(--tl-tannery); }
em.gold { font-style: italic; color: var(--tl-gold-deep); }

/* Footer */
.tl-footer { background: var(--tl-ink); color: var(--tl-bone); padding: 80px 0 32px; margin-top: 96px; }
.tl-footer-grid { display: grid; grid-template-columns: 1.4fr 1fr 1fr 1.2fr; gap: 40px; max-width: 1240px; margin: 0 auto; padding: 0 24px; }
.tl-footer-col { display: flex; flex-direction: column; gap: 12px; }
.tl-footer-col a { color: var(--tl-bone); text-decoration: none; font-size: 14px; }
.tl-footer-col a:hover { color: var(--tl-gold); }
.tl-footer-bottom {
  margin-top: 48px; padding: 16px 24px 0;
  border-top: 1px solid var(--tl-line-dark);
  display: flex; justify-content: space-between;
  font-family: var(--tl-mono); font-size: 11px; color: var(--tl-mute);
  max-width: 1240px; margin-left: auto; margin-right: auto;
}

/* Tags */
.tl-tag {
  display: inline-flex; align-items: center; gap: 6px;
  background: var(--tl-paper); color: var(--tl-ink);
  font-size: 12px; padding: 6px 12px; border-radius: 999px;
}
.tl-tag--filled { background: var(--tl-tannery); color: var(--tl-bone); font-weight: 500; }
.tl-chip {
  background: transparent; color: var(--tl-ink); border: 1px solid var(--tl-line);
  border-radius: 999px; padding: 10px 16px; font-size: 13px;
  font-family: var(--tl-sans); cursor: pointer;
  transition: all 140ms cubic-bezier(0.3,0,0.2,1);
}
.tl-chip:hover { border-color: var(--tl-ink); }
.tl-chip--active { background: var(--tl-ink); color: var(--tl-bone); border-color: var(--tl-ink); }

/* Section spacing */
section { padding: 96px 0; }
section.compact { padding: 64px 0; }
hr.tl-rule { border: 0; border-top: 1px solid var(--tl-line); margin: 0; }

/* Product card */
.tl-product { display: flex; flex-direction: column; gap: 14px; }
.tl-product-img {
  aspect-ratio: 4/5; overflow: hidden; border-radius: 8px;
  background: var(--tl-paper);
}
.tl-product-img > div {
  width: 100%; height: 100%; background-size: cover; background-position: center;
  transition: transform 420ms cubic-bezier(0.2,0.7,0.2,1);
}
.tl-product:hover .tl-product-img > div { transform: scale(1.02); }
.tl-product-meta { display: flex; flex-direction: column; gap: 4px; }
.tl-product-name { font-family: var(--tl-serif); font-weight: 500; font-size: 22px; line-height: 1.2; }
.tl-product-spec { font-size: 13px; color: var(--tl-mute-2); }
.tl-product-price { font-size: 14px; margin-top: 6px; }

/* Mini cart sheet */
.tl-cart {
  position: fixed; right: 0; top: 0; bottom: 0; width: 420px;
  background: var(--tl-ink); color: var(--tl-bone);
  transform: translateX(100%); transition: transform 320ms cubic-bezier(0.2,0.7,0.2,1);
  z-index: 100; display: flex; flex-direction: column;
  box-shadow: 0 24px 48px -16px rgba(0,0,0,0.4);
}
.tl-cart.open { transform: translateX(0); }
.tl-cart-overlay {
  position: fixed; inset: 0; background: rgba(10,10,10,0.4);
  opacity: 0; pointer-events: none; transition: opacity 240ms;
  z-index: 99;
}
.tl-cart-overlay.open { opacity: 1; pointer-events: all; }
.tl-cart-header {
  display: flex; justify-content: space-between; align-items: center;
  padding: 20px 24px; border-bottom: 1px solid var(--tl-line-dark);
}
.tl-cart-body { flex: 1; overflow-y: auto; padding: 8px 24px; }
.tl-cart-line {
  display: grid; grid-template-columns: 80px 1fr auto;
  gap: 16px; padding: 20px 0; border-bottom: 1px solid var(--tl-line-dark);
}
.tl-cart-line:last-child { border-bottom: 0; }
.tl-cart-thumb { width: 80px; height: 100px; border-radius: 4px; background-size: cover; background-position: center; }
.tl-cart-footer { padding: 24px; border-top: 1px solid var(--tl-line-dark); display: flex; flex-direction: column; gap: 16px; }

