<script type="text/babel" data-presets="env,react">
const PRODUCTS = {
  carry: { name: 'The Carry', price: 680, image: '../../assets/mood-bag-blue.jpg',
    tagline: 'A 14-litre tote in our own veg-tanned leather. Built around the way a single bag actually gets used in a single week.',
    tags: ['Veg-tanned', '1.4 mm temple', '14 L', 'Made in Chennai'] },
  hold:  { name: 'The Hold', price: 1240, image: '../../assets/emblem-on-leather.png',
    tagline: 'A weekend duffle with a flat bottom and a strap that softens by year two.',
    tags: ['Cognac', '32 L', 'Brass hardware', 'Made in Chennai'] },
  day:   { name: 'The Day', price: 220, image: '../../assets/mood-portrait-warm.jpg',
    tagline: 'Eight cards, two notes, no zip. The wallet you stop noticing.',
    tags: ['Bifold', 'Ink black', '8 cards', 'Made in Chennai'] },
};

const App = () => {
  const [view, setView] = React.useState('home');     // home | pdp
  const [activeProduct, setActiveProduct] = React.useState(null);
  const [lines, setLines] = React.useState([]);
  const [cartOpen, setCartOpen] = React.useState(false);

  const openProduct = (key) => { setActiveProduct(PRODUCTS[key]); setView('pdp'); window.scrollTo(0,0); };
  const addToBag = (p) => {
    setLines(prev => {
      const i = prev.findIndex(l => l.name === p.name);
      if (i >= 0) { const next = [...prev]; next[i] = { ...next[i], qty: next[i].qty + 1 }; return next; }
      return [...prev, { name: p.name, price: p.price, image: p.image, qty: 1 }];
    });
    setCartOpen(true);
  };
  const removeLine = (i) => setLines(prev => prev.filter((_,k) => k !== i));
  const bagCount = lines.reduce((s,l) => s + l.qty, 0);

  return (
    <>
      <TLHeader onCartClick={() => setCartOpen(true)} bagCount={bagCount} />
      {view === 'home' ? (
        <>
          <TLHero />
          <TLPillars />
          <div onClick={(e) => {
            // Click any product card → PDP
            const card = e.target.closest('.tl-product');
            if (!card) return;
            const idx = [...card.parentElement.children].indexOf(card);
            openProduct(['carry','hold','day'][idx]);
          }}>
            <TLProductRow onAdd={addToBag} />
          </div>
          <TLManifesto />
          <TLTannery />
          <TLJournalRow />
        </>
      ) : (
        <TLProductDetail
          product={activeProduct}
          onAdd={(p) => addToBag(p)}
          onBack={() => setView('home')}
        />
      )}
      <TLFooter />
      <TLCart open={cartOpen} lines={lines} onClose={() => setCartOpen(false)} onRemove={removeLine} />
    </>
  );
};

ReactDOM.createRoot(document.getElementById('root')).render(<App />);
</script>
